-- 2. Broadstairs × SEO
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'seo',
  'broadstairs',
  'Search visibility in Broadstairs operates on two distinct cycles that most businesses fail to address. From May to September, tourists flood Google with searches for restaurants near Viking Bay, things to do in Broadstairs, and holiday accommodation on the Thanet coast. From October to April, the resident population of twenty-five thousand drives a completely different set of searches for local tradespeople, professional services, and everyday amenities. Businesses that only optimise for one cycle leave half their potential revenue on the table. Our SEO campaigns are built around Broadstairs''s dual-season reality, capturing tourist traffic when it peaks and maintaining year-round visibility for the local searches that sustain businesses through the quieter months. We target the specific terms, locations, and search behaviours that actually drive revenue in this coastal town.',
  'Broadstairs''s search landscape reflects its position as a coastal town with strong tourism appeal and a committed residential community. Viking Bay, Louisa Bay, and Stone Bay generate beach and activity-related searches through summer. The Dickens heritage around Bleak House drives cultural tourism searches year-round. The High Street and York Gate area attract retail and dining searches. Pierremont Park and Victoria Gardens appear in family activity searches. The train connection to London Victoria, while longer than high-speed alternatives, still brings a small commuter contingent whose search behaviour mirrors urban expectations.',
  'SEO competition in Broadstairs is heavily influenced by tourism aggregators. Visit Thanet, TripAdvisor, and booking platforms dominate tourist-related search results, pushing individual business websites down the rankings. For residential service searches, competition is moderate but growing as more Thanet businesses invest in digital marketing. The Google Map Pack for Broadstairs trades is less contested than in larger Kent towns, presenting a clear opportunity for businesses willing to invest.',
  'We treat Broadstairs SEO as a dual-campaign discipline. Tourist-facing businesses get seasonal content calendars that build authority for summer search terms months in advance, so pages are ranking when visitors start planning. Service businesses get hyper-local targeting across Broadstairs postcodes and surrounding Thanet areas. Google Business Profile optimisation is central to both approaches, with review generation strategies tailored to the different ways tourists and residents leave feedback.',
  '{"population": 25000, "growth": "Stable with seasonal tourism multiplier", "business_districts": ["High Street", "Viking Bay", "York Gate", "Harbour Street"], "key_fact": "Dual-season search pattern: tourist surges May-September, residential year-round"}',
  '[{"title": "Tourism aggregators burying Broadstairs businesses", "description": "Visit Thanet, TripAdvisor, and major booking platforms dominate the first page for almost every tourist-related Broadstairs search. Individual restaurants near Viking Bay and holiday lets along the seafront are pushed to page two or beyond, forcing them to pay commission to platforms that outrank them for their own town."}, {"title": "Off-season search visibility dropping to zero", "description": "Broadstairs hospitality businesses invest in summer marketing but neglect SEO for the quieter months. Their sites lose ranking momentum over winter, meaning they start every spring fighting to regain positions they held the previous August. This annual cycle wastes budget and hands the early-season advantage to competitors."}, {"title": "Google Map Pack underutilised by Broadstairs trades", "description": "Local tradespeople and service providers in Broadstairs frequently have incomplete Google Business Profiles with few reviews and no photos. The Map Pack positions that drive the most phone calls sit vacant or occupied by competitors from Ramsgate and Margate who have optimised their profiles for wider Thanet coverage."}]',
  '[{"title": "Dual-season SEO strategy for Broadstairs", "description": "We run parallel SEO campaigns: one targeting tourist search terms that peak in summer, built with content published months ahead to establish ranking authority before visitors start searching; and one targeting year-round residential searches that sustain your business through the quieter coastal months."}, {"title": "Aggregator competition strategy for hospitality", "description": "We cannot outrank TripAdvisor on domain authority alone, but we can outperform them on local relevance. Broadstairs-specific content, structured data markup, Google Business Profile optimisation, and niche long-tail targeting ensure your business appears for the specific searches that aggregator pages miss."}, {"title": "Google Map Pack dominance across Thanet", "description": "We fully optimise your Google Business Profile with Broadstairs-specific categories, professional photography, structured review generation, and service area targeting that covers the wider Thanet coast. Our clients consistently secure top-three Map Pack positions for their primary local keywords."}]',
  '[{"question": "How long does SEO take to show results in Broadstairs?", "answer": "For residential service searches with moderate competition, most Broadstairs clients see ranking improvements within eight to twelve weeks. Tourist-related keywords are more competitive due to aggregator dominance and typically require four to six months of sustained work to reach the first page."}, {"question": "Can SEO help me compete with TripAdvisor and Visit Thanet?", "answer": "Yes, through a targeted approach. While these platforms have enormous domain authority, they serve broad results. We target specific long-tail searches that tourists actually use, like best seafood restaurant near Viking Bay, where a well-optimised local page can outrank generic directory listings."}, {"question": "Should I focus on Broadstairs searches or wider Thanet?", "answer": "Both. We build your core authority around Broadstairs-specific terms, then extend coverage to Thanet-wide searches and neighbouring areas like Ramsgate and Margate. This layered approach maximises your total search visibility without diluting your local relevance."}, {"question": "How do you handle the seasonal drop in Broadstairs searches?", "answer": "We maintain year-round content publication and link building so your site never loses momentum. Residential service content keeps traffic flowing through winter, while early-year tourist content starts building ranking authority well before the summer search surge begins."}]',
  'authority'
)
