-- 3. Broadstairs × Lead Capture
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'lead-capture',
  'broadstairs',
  'Broadstairs businesses face a lead capture challenge unlike anywhere else in Kent. During summer, thousands of tourists browse local business websites from their phones while walking between Viking Bay and Morelli''s, making split-second decisions about where to eat, what to book, and who to hire. In winter, the town''s twenty-five thousand residents search for services at a steadier pace but expect the same instant response they get from national brands. In both seasons, the businesses that capture visitor details and follow up fastest win the work. A phone number and a contact form are not enough when your competitor has an instant booking widget and automated confirmation emails. Our lead capture systems are designed for the specific rhythms of Broadstairs, converting seasonal browsers and year-round locals into contactable, qualified leads.',
  'Broadstairs''s lead generation dynamics split along seasonal lines. Summer brings high-volume, low-intent browsing from tourists comparing options around Viking Bay, the High Street, and the seafront. These visitors need frictionless booking and instant confirmation. Year-round residents generate lower-volume but higher-intent enquiries for services from plumbing to accountancy, where speed of response determines who gets the job. The Folk Week and Food Festival create intense short-duration traffic spikes where lead capture must work flawlessly under pressure.',
  'Most Broadstairs businesses rely on phone calls and basic email contact forms. Restaurants near Viking Bay increasingly use third-party booking platforms that take commission, while holiday let owners depend on Airbnb and Booking.com rather than capturing direct leads. Service businesses across the town have almost no structured lead capture, losing potential customers who browse their site outside business hours.',
  'We design lead capture systems around the two distinct Broadstairs customer types. Tourist-facing businesses get integrated booking widgets, instant confirmation sequences, and event-specific landing pages for Folk Week and Food Festival periods. Service businesses get quote calculators, callback request forms, and automated follow-up sequences that engage evening and weekend browsers. Every system is mobile-first because that is how Broadstairs customers search.',
  '{"population": 25000, "growth": "Seasonal tourism multiplies effective market significantly", "business_districts": ["High Street", "Viking Bay", "Harbour Street", "seafront"], "key_fact": "Folk Week and Food Festival create intense short-duration lead capture opportunities"}',
  '[{"title": "Tourist browsers leaving Broadstairs sites without booking", "description": "A visitor standing near Viking Bay searches for somewhere to eat. They tap your site, see a phone number and a contact form, and move on to a competitor with an instant booking button. During peak season, Broadstairs hospitality businesses lose dozens of covers daily to competitors with better lead capture."}, {"title": "Off-hours enquiries going cold overnight", "description": "A Broadstairs resident searches for a local electrician at nine in the evening and fills in your contact form. You respond at eight the next morning, but they already called the competitor whose automated system sent an instant acknowledgement and a morning callback confirmation. After-hours leads need after-hours responses."}, {"title": "Festival and event traffic wasted without capture", "description": "Broadstairs Folk Week draws tens of thousands of visitors over a single week. The Food Festival packs the seafront. These intense traffic spikes generate massive browsing volume, but businesses without event-specific lead capture let the opportunity pass without converting a fraction of the interest into bookings or enquiries."}]',
  '[{"title": "Instant booking integration for Broadstairs hospitality", "description": "We embed real-time booking widgets directly into your Broadstairs website, eliminating the need for visitors to call or email. Tourists browsing near Viking Bay can reserve a table, book an activity, or secure accommodation in under thirty seconds, with automated confirmation hitting their inbox immediately."}, {"title": "Automated follow-up for after-hours enquiries", "description": "Every lead captured outside business hours triggers an instant personalised acknowledgement, followed by a timed sequence that keeps your Broadstairs business front of mind. By the time you check your phone in the morning, the prospect has already received professional communication and a confirmed callback time."}, {"title": "Event-specific landing pages for peak periods", "description": "We build dedicated landing pages for Broadstairs Folk Week, the Food Festival, and other peak events with targeted lead capture forms, special offers, and booking tools designed for the specific audience each event attracts. These pages go live weeks before the event, capturing early planners."}]',
  '[{"question": "What lead capture works best for Broadstairs tourism businesses?", "answer": "Integrated booking widgets and instant confirmation systems consistently outperform basic contact forms for hospitality businesses around Viking Bay and the seafront. Visitors want to book immediately from their phone without calling, and automated confirmation removes any doubt that their booking is secured."}, {"question": "Can lead capture help during Broadstairs Folk Week?", "answer": "Absolutely. We build event-specific landing pages with targeted offers and booking tools designed for the Folk Week audience. These pages launch several weeks before the event, capturing early planners, and run throughout the week to convert spontaneous visitors into bookings."}, {"question": "How does lead capture work for Broadstairs service businesses?", "answer": "For trades and professional services, we implement quote calculators, callback request forms, and downloadable guides that capture visitor details in exchange for immediate value. Automated follow-up sequences then nurture these leads until they convert into booked appointments."}, {"question": "Will lead capture work on my existing Broadstairs website?", "answer": "Yes. We can add lead capture tools to any existing website without a full redesign. Pop-ups, slide-ins, embedded forms, and booking widgets can all be implemented on your current Broadstairs site, typically within one to two weeks."}]',
  'lead-gen'
)
