-- 6. Broadstairs × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'broadstairs',
  'Social media in Broadstairs operates differently from most Kent towns because the audience shifts dramatically with the seasons. In summer, your followers include thousands of tourists sharing Viking Bay sunset photos, tagging restaurants on Harbour Street, and searching Instagram for things to do in Broadstairs. In winter, your audience shrinks to the loyal resident community that sustains your business year-round. Serving both audiences from a single set of social profiles requires strategic setup, not guesswork. Most Broadstairs businesses post sporadically, switch between personal and business accounts, and have no content plan for the quieter months. We set up professional social media foundations for Broadstairs businesses that work for both audiences, building local community engagement through winter and capturing tourist attention when the seafront fills up in summer.',
  'Broadstairs''s social media landscape is visually rich and community-driven. Viking Bay, Louisa Bay, and Stone Bay provide stunning photographic content that performs well on visual platforms. The Folk Week, Food Festival, and Dickens Festival create concentrated periods of social media activity and hashtag usage. The independent High Street businesses form an informal mutual-promotion network through tagging and sharing. Morelli''s and Bleak House serve as landmark geo-tags that draw engagement. Victoria Gardens and Pierremont Park feature in family and lifestyle content throughout the year.',
  'Social media quality among Broadstairs businesses is inconsistent. Tourism and hospitality venues near Viking Bay tend to have the strongest presence, leveraging their photogenic locations for Instagram and Facebook content. Service businesses and trades have minimal social media presence, often limited to dormant Facebook pages with outdated information. A small number of independent shops on the High Street use social media effectively for community engagement, but the majority post irregularly with no strategic foundation.',
  'We set up Broadstairs social profiles with dual-audience architecture from day one. Profile bios, highlight categories, and content pillars are structured to serve both local residents and seasonal visitors. We create content calendars aligned to Broadstairs events including Folk Week, the Food Festival, and the Dickens Festival. Geo-tagging strategies leverage high-traffic locations like Viking Bay and Morelli''s. Brand-consistent templates ensure every post reinforces your professional identity regardless of who is posting.',
  '{"population": 25000, "growth": "Stable residential with massive seasonal social media reach expansion", "business_districts": ["High Street", "Viking Bay", "Harbour Street", "seafront"], "key_fact": "Visual coastal setting and major events create exceptional organic social media content opportunities"}',
  '[{"title": "Broadstairs businesses with dormant or inconsistent social profiles", "description": "A potential customer searches for your Broadstairs business on Instagram and finds a profile that has not been updated in three months, with a blurry logo and no contact information in the bio. They move on to a competitor whose profile looks professional and active. Dormant social media is worse than no social media at all."}, {"title": "No strategy for seasonal audience shifts", "description": "Broadstairs businesses post tourist-friendly content all summer, then go silent when the visitors leave. The resident community that keeps them alive through winter sees a business that apparently only cares about seasonal trade. Without a year-round content strategy, social media damages local relationships rather than building them."}, {"title": "Missing the Folk Week and Food Festival social surge", "description": "When Folk Week or the Food Festival fills Broadstairs, social media activity around the town spikes enormously. Businesses without prepared content, relevant hashtags, and event-specific promotions miss the single biggest organic reach opportunity of the year while competitors capture all the attention."}]',
  '[{"title": "Professional dual-audience social media setup", "description": "We configure your Broadstairs social profiles with optimised bios, branded highlight categories, and content structures that serve both tourist visitors and year-round residents. Every profile element is designed to convert browsers into followers and followers into customers regardless of the season."}, {"title": "Event-aligned content calendars for Broadstairs", "description": "We build annual content calendars structured around Broadstairs events: Folk Week, Food Festival, Dickens Festival, and seasonal transitions. Pre-planned content ensures you capture every major engagement opportunity without scrambling to create posts at the last minute."}, {"title": "Brand-consistent templates and visual guidelines", "description": "We create a library of branded social media templates for posts, stories, and reels that any team member can use. Consistent visual identity across every post reinforces your professional credibility and makes your Broadstairs business instantly recognisable in busy social feeds."}]',
  '[{"question": "Which social media platforms work best for Broadstairs businesses?", "answer": "Instagram performs exceptionally well for Broadstairs hospitality and retail businesses due to the photogenic coastal setting. Facebook remains the strongest platform for community engagement with local residents. Google Business Profile is essential for search visibility. We recommend the right combination based on your specific audience."}, {"question": "How do you handle the seasonal social media shift in Broadstairs?", "answer": "We build content calendars with distinct seasonal phases. Summer content targets visitors with location tags, event hashtags, and tourist-friendly posts. Winter content focuses on community engagement, behind-the-scenes content, and offers for loyal local customers. The transition is planned, not reactive."}, {"question": "Can you set up social media for a new Broadstairs business?", "answer": "Yes. We build social profiles from scratch for new Broadstairs businesses, including all platform setup, brand-consistent visuals, optimised bios, and a launch content plan that establishes your presence before you even open your doors. This is particularly effective ahead of the summer season."}, {"question": "Do you manage social media ongoing or just set it up?", "answer": "This service focuses on professional setup and strategic foundations. We deliver configured profiles, content calendars, templates, and guidelines that enable you or your team to maintain a consistent, effective social media presence. Ongoing management is available as a separate service if needed."}]',
  'trust'
)
